            if self.rows[r] >= k:
                c = self.filled[r]
                self.rows[r] -= k
                self.filled[r] += k
                return [r, c]
        return []

    def scatter(self, k, maxRow):
        total = sum(self.rows[r] for r in range(maxRow + 1))
        if total < k:
            return False
        remaining = k
        for r in range(maxRow + 1):
            take = min(remaining, self.rows[r])
            self.rows[r] -= take
            self.filled[r] += take
            remaining -= take
            if remaining == 0:
