class BookMyShow:
    def __init__(self, n: int, m: int):
        self.n = n
        self.m = m
        # Segment tree: size 4*n
        # mx[i] = max remaining seats in range, sm[i] = sum remaining seats
        self.mx = [m] * (4 * n)
        self.sm = [0] * (4 * n)
        # Build: each leaf holds m seats
        def build(node, l, r):
            if l == r:
                self.sm[node] = m
                self.mx[node] = m
                return
            mid = (l + r) // 2
            build(2*node, l, mid)
            build(2*node+1, mid+1, r)
            self.sm[node] = self.sm[2*node] + self.sm[2*node+1]
            self.mx[node] = max(self.mx[2*node], self.mx[2*node+1])
        build(1, 0, n-1)

    def _update(self, node, l, r, idx, delta):
        if l == r:
            self.mx[node] -= delta
            self.sm[node] -= delta
            return
        mid = (l + r) // 2
        if idx <= mid:
            self._update(2*node, l, mid, idx, delta)
        else:
            self._update(2*node+1, mid+1, r, idx, delta)
        self.sm[node] = self.sm[2*node] + self.sm[2*node+1]
        self.mx[node] = max(self.mx[2*node], self.mx[2*node+1])

    def _query_sum(self, node, l, r, ql, qr):
        if qr < l or r < ql:
            return 0
        if ql <= l and r <= qr:
            return self.sm[node]
        mid = (l + r) // 2
        return self._query_sum(2*node, l, mid, ql, qr) + self._query_sum(2*node+1, mid+1, r, ql, qr)

    def _find_gather(self, node, l, r, ql, qr, k):
        # Find leftmost index in [ql,qr] with remaining >= k
        if qr < l or r < ql or self.mx[node] < k:
            return -1
        if l == r:
            return l
        mid = (l + r) // 2
        res = self._find_gather(2*node, l, mid, ql, qr, k)
        if res != -1:
            return res
        return self._find_gather(2*node+1, mid+1, r, ql, qr, k)

    def gather(self, k: int, maxRow: int):
        row = self._find_gather(1, 0, self.n-1, 0, maxRow, k)
        if row == -1:
            return []
        # seat = m - current_remaining
        remaining_before = self._query_sum(1, 0, self.n-1, row, row)
        seat = self.m - remaining_before
        self._update(1, 0, self.n-1, row, k)
        return [row, seat]

    def scatter(self, k: int, maxRow: int) -> bool:
        total = self._query_sum(1, 0, self.n-1, 0, maxRow)
        if total < k:
            return False
        remaining = k
        # Fill rows greedily from left; find first non-full row
        # Use a pointer tracked as part of scatter
        # Simple approach: walk via segment tree finding leftmost row with space
        r = 0
        while remaining > 0 and r <= maxRow:
            avail = self._query_sum(1, 0, self.n-1, r, r)
            if avail > 0:
                take = min(remaining, avail)
                self._update(1, 0, self.n-1, r, take)
                remaining -= take
            r += 1
        return True

