class BookMyShow {
    constructor(n, m) {
        this.n = n;
        this.m = m;
        this.mx = new Array(4 * n).fill(m);
        this.sm = new Array(4 * n).fill(0);
        this._build(1, 0, n - 1);
    }
    _build(node, l, r) {
        if (l === r) { this.sm[node] = this.m; this.mx[node] = this.m; return; }
        const mid = (l + r) >> 1;
        this._build(2*node, l, mid);
        this._build(2*node+1, mid+1, r);
        this.sm[node] = this.sm[2*node] + this.sm[2*node+1];
        this.mx[node] = Math.max(this.mx[2*node], this.mx[2*node+1]);
    }
    _update(node, l, r, idx, delta) {
        if (l === r) { this.mx[node] -= delta; this.sm[node] -= delta; return; }
        const mid = (l + r) >> 1;
        if (idx <= mid) this._update(2*node, l, mid, idx, delta);
        else this._update(2*node+1, mid+1, r, idx, delta);
        this.sm[node] = this.sm[2*node] + this.sm[2*node+1];
        this.mx[node] = Math.max(this.mx[2*node], this.mx[2*node+1]);
    }
    _querySum(node, l, r, ql, qr) {
        if (qr < l || r < ql) return 0;
        if (ql <= l && r <= qr) return this.sm[node];
        const mid = (l + r) >> 1;
        return this._querySum(2*node, l, mid, ql, qr) + this._querySum(2*node+1, mid+1, r, ql, qr);
    }
    _findGather(node, l, r, ql, qr, k) {
        if (qr < l || r < ql || this.mx[node] < k) return -1;
        if (l === r) return l;
        const mid = (l + r) >> 1;
        const res = this._findGather(2*node, l, mid, ql, qr, k);
        if (res !== -1) return res;
        return this._findGather(2*node+1, mid+1, r, ql, qr, k);
    }
    gather(k, maxRow) {
        const row = this._findGather(1, 0, this.n-1, 0, maxRow, k);
        if (row === -1) return [];
        const remainingBefore = this._querySum(1, 0, this.n-1, row, row);
        const seat = this.m - remainingBefore;
        this._update(1, 0, this.n-1, row, k);
        return [row, seat];
    }
    scatter(k, maxRow) {
        const total = this._querySum(1, 0, this.n-1, 0, maxRow);
        if (total < k) return false;
        let remaining = k;
        let r = 0;
        while (remaining > 0 && r <= maxRow) {
            const avail = this._querySum(1, 0, this.n-1, r, r);
            if (avail > 0) {
                const take = Math.min(remaining, avail);
                this._update(1, 0, this.n-1, r, take);
                remaining -= take;
            }
            r++;
        }
        return true;
    }
}
